mapper.select:
SELECT c.id AS circleId, c.owner_id AS ownerId, o.nickname AS ownerName, c.name, c.category_id AS categoryId, COALESCE(cc.name, '') AS categoryName, COALESCE(c.intro, '') AS intro, CASE c.type WHEN 0 THEN 'PUBLIC' ELSE 'PRIVATE' END AS type, c.member_count AS memberCount, (SELECT COUNT(*) FROM post WHERE circle_id = c.id AND deleted = 0) AS postCount, CASE c.status WHEN 0 THEN 'OFFLINE' WHEN 1 THEN 'ONLINE' WHEN 2 THEN 'PENDING' WHEN 3 THEN 'REJECTED' ELSE 'OFFLINE' END AS status, CASE WHEN c.recommend = 1 THEN true ELSE false END AS recommended, COALESCE(c.avatar, '') AS icon, COALESCE(c.banner, '') AS banner, c.create_time AS createTime FROM circle c LEFT JOIN `user` o ON c.owner_id = o.id AND o.deleted = 0 LEFT JOIN circle_category cc ON c.category_id = cc.id
c.deleted = 0
AND c.status = #{status}
AND c.category_id = #{categoryId}
AND c.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY c.member_count DESC
